<?php
namespace App\Controllers; use App\Models\Assessment;
class ApiAssessmentController { public function store(){ $in=$_POST ?: json_decode(file_get_contents('php://input'),true) ?: []; foreach(['company_name','company_rut','contact_name','email','industry'] as $f){ if(empty($in[$f])) \json_response(['success'=>false,'message'=>'Campo requerido: '.$f],422);} if(!filter_var($in['email'],FILTER_VALIDATE_EMAIL)) \json_response(['success'=>false,'message'=>'Email inválido'],422); if(empty($in['answers'])||!is_array($in['answers'])) \json_response(['success'=>false,'message'=>'Respuestas requeridas'],422); $res=(new Assessment)->store($in); \json_response(['success'=>true,'client_id'=>$res['client_id'],'final_score'=>$res['final_score'],'risk_level'=>$res['risk_level'],'recommendation'=>$res['recommendation']]);}}
